import java.io.File;

public class ImageConverter {
    private static final String IM_COMMAND = "convert";

    public static void convertImage(String inputFileName, String outputFileName, String format) throws Exception {
        File inputFile = new File(inputFileName);
        File outputFile = new File(outputFileName);

        ProcessBuilder builder = new ProcessBuilder(IM_COMMAND, inputFile.getAbsolutePath(), "-format", format, outputFile.getAbsolutePath());
        Process process = builder.start();

        int exitValue = process.waitFor();
        if (exitValue != 0) {
            throw new Exception("Image conversion failed with error code: " + exitValue);
        }
    }
}